404	func loadOrUnloadModel(cmd *cobra.Command, opts *runOptions) error {
405		p := progress.NewProgress(os.Stderr)
406		defer p.StopAndClear()
407	
408		spinner := progress.NewSpinner("")
409		p.Add("", spinner)
410	
411		client, err := api.ClientFromEnvironment()
412		if err != nil {
413			return err
414		}
415	
416		requestedCloud := modelref.HasExplicitCloudSource(opts.Model)
417	
418		if info, err := client.Show(cmd.Context(), &api.ShowRequest{Model: opts.Model}); err != nil {
419			return err
420		} else if info.RemoteHost != "" || requestedCloud {
421			// Cloud model, no need to load/unload
422	
423			isCloud := requestedCloud || strings.HasPrefix(info.RemoteHost, "https://ollama.com")
424	
425			// Check if user is signed in for ollama.com cloud models
426			if isCloud {
427				if _, err := client.Whoami(cmd.Context()); err != nil {
428					return err
429				}
430			}
431	
432			if opts.ShowConnect {
433				p.StopAndClear()
434				remoteModel := info.RemoteModel
435				if remoteModel == "" {
436					remoteModel = opts.Model
437				}
438				if isCloud {
439					fmt.Fprintf(os.Stderr, "Connecting to '%s' on 'ollama.com' ⚡\n", remoteModel)
440				} else {
441					fmt.Fprintf(os.Stderr, "Connecting to '%s' on '%s'\n", remoteModel, info.RemoteHost)
442				}
443			}
444	
445			return nil
446		}
447	
448		req := &api.GenerateRequest{
449			Model:     opts.Model,
450			KeepAlive: opts.KeepAlive,
451	
452			// pass Think here so we fail before getting to the chat prompt if the model doesn't support it
453			Think: opts.Think,
454		}
455	
456		return client.Generate(cmd.Context(), req, func(r api.GenerateResponse) error {
457			return nil
458		})
459	}
