65	func TestClientStream(t *testing.T) {
66		testCases := []struct {
67			name      string
68			responses []any
69			wantErr   string
70		}{
71			{
72				name: "immediate error response",
73				responses: []any{
74					testError{
75						message:    "test error message",
76						statusCode: http.StatusBadRequest,
77					},
78				},
79				wantErr: "test error message",
80			},
81			{
82				name: "error after successful chunks, ok response",
83				responses: []any{
84					ChatResponse{Message: Message{Content: "partial response 1"}},
85					ChatResponse{Message: Message{Content: "partial response 2"}},
86					testError{
87						message:    "mid-stream error",
88						statusCode: http.StatusOK,
89					},
90				},
91				wantErr: "mid-stream error",
92			},
93			{
94				name: "http status error takes precedence over general error",
95				responses: []any{
96					testError{
97						message:    "custom error message",
98						statusCode: http.StatusInternalServerError,
99					},
100				},
101				wantErr: "500",
102			},
103			{
104				name: "successful stream completion",
105				responses: []any{
106					ChatResponse{Message: Message{Content: "chunk 1"}},
107					ChatResponse{Message: Message{Content: "chunk 2"}},
108					ChatResponse{
109						Message:    Message{Content: "final chunk"},
110						Done:       true,
111						DoneReason: "stop",
112					},
113				},
114			},
115			{
116				name: "plain text error response",
117				responses: []any{
118					"internal server error",
119				},
120				wantErr: "internal server error",
121			},
122			{
123				name: "HTML error page",
124				responses: []any{
125					"<html><body>404 Not Found</body></html>",
126				},
127				wantErr: "404 Not Found",
128			},
129		}
130	
131		for _, tc := range testCases {
132			t.Run(tc.name, func(t *testing.T) {
133				ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
134					flusher, ok := w.(http.Flusher)
135					if !ok {
136						t.Fatal("expected http.Flusher")
137					}
138	
139					w.Header().Set("Content-Type", "application/x-ndjson")
140	
141					for _, resp := range tc.responses {
142						if errResp, ok := resp.(testError); ok {
143							w.WriteHeader(errResp.statusCode)
144							err := json.NewEncoder(w).Encode(map[string]string{
145								"error": errResp.message,
146							})
147							if err != nil {
148								t.Fatal("failed to encode error response:", err)
149							}
150							return
151						}
152	
153						if str, ok := resp.(string); ok {
154							fmt.Fprintln(w, str)
155							flusher.Flush()
156							continue
157						}
158	
159						if err := json.NewEncoder(w).Encode(resp); err != nil {
160							t.Fatalf("failed to encode response: %v", err)
161						}
162						flusher.Flush()
163					}
164				}))
165				defer ts.Close()
166	
167				client := NewClient(&url.URL{Scheme: "http", Host: ts.Listener.Addr().String()}, http.DefaultClient)
168	
169				var receivedChunks []ChatResponse
170				err := client.stream(t.Context(), http.MethodPost, "/v1/chat", nil, func(chunk []byte) error {
171					var resp ChatResponse
172					if err := json.Unmarshal(chunk, &resp); err != nil {
173						return fmt.Errorf("failed to unmarshal chunk: %w", err)
174					}
175					receivedChunks = append(receivedChunks, resp)
176					return nil
177				})
178	
179				if tc.wantErr != "" {
180					if err == nil {
181						t.Fatal("expected error but got nil")
182					}
183					if !strings.Contains(err.Error(), tc.wantErr) {
184						t.Errorf("expected error containing %q, got %v", tc.wantErr, err)
185					}
186					return
187				}
188				if err != nil {
189					t.Errorf("unexpected error: %v", err)
190				}
191			})
192		}
193	}
