func RenameModel(src, dst model.Name) error {
	// 1. Validate both names are fully qualified
	if !dst.IsFullyQualified() {
		return model.Unqualified(dst)
	}
	if !src.IsFullyQualified() {
		return model.Unqualified(src)
	}

	// 2. Check source exists
	srcManifest, err := manifest.ParseNamedManifest(src)
	if err != nil {
		return err
	}

	// 3. Check destination doesn't exist
	existing, _ := manifest.Manifests(true)
	if _, exists := existing[dst]; exists {
		return fmt.Errorf("destination model already exists")
	}

	// 4. Copy the file
	if err := CopyModel(src, dst); err != nil {
		return err
	}

	// 5. Remove source
	if err := srcManifest.Remove(); err != nil {
		// Try to clean up destination on failure
		os.Remove(filepath.Join(manifests, dst.Filepath()))
		return err
	}

	return nil
}
